from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def _article(word: str) -> str:
    """Return appropriate indefinite article ('a' or 'an') for a given word."""
    return "an" if word[0].lower() in "aeiou" else "a"


def _format_nationality(nat: str) -> str:
    """Convert nationality strings to a natural phrase."""
    # Strip trailing plural 's' (e.g., Americans -> American)
    nat_clean = nat.rstrip("s")
    # Handle common country forms
    if nat_clean.lower() in {"united states", "united kingdom", "united arab emirates"}:
        return f"is from the {nat_clean}"
    return f"is {_article(nat_clean)} {nat_clean}"


def _quote_if_needed(text: str) -> str:
    """Ensure that quoted literals are wrapped in double quotes."""
    if (text.startswith('"') and text.endswith('"')) or (text.startswith("'") and text.endswith("'")):
        return text
    # Add quotes if the text contains spaces or special characters
    if any(ch in text for ch in " ,;:"):
        return f'"{text}"'
    return text


def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a comics character (or related entities)
    into a single fluent English sentence.
    """
    if not triples:
        return ""

    parts: list[str] = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        if p == "alternativeName":
            parts.append(f"{s} is also known as {o}")
        elif p == "creator":
            parts.append(f"{s} was created by {o}")
        elif p == "fullName":
            parts.append(f"{s}'s full name is {o}")
        elif p == "foundedBy":
            parts.append(f"{s} was founded by {o}")
        elif p == "keyPerson":
            parts.append(f"{s} has key person {o}")
        elif p == "city":
            parts.append(f"{s} is located in {o}")
        elif p == "product":
            parts.append(f"{s} produces {o}")
        elif p == "lastAired":
            parts.append(f"The last episode of {s} aired on {o}")
        elif p == "starring":
            parts.append(f"{s} stars {o}")
        elif p == "firstAppearanceInFilm":
            parts.append(f"{s} first appeared in the film {o}")
        elif p == "voice":
            parts.append(f"{s} is voiced by {o}")
        elif p == "distributor":
            parts.append(f"The film {s} was distributed by {o}")
        elif p == "birthPlace":
            parts.append(f"{s} was born in {o}")
        elif p == "nationality":
            parts.append(f"{s} is a {o} national")
        elif p == "award":
            parts.append(f"{s} received the {o}")
        elif p == "broadcastedBy":
            parts.append(f"{s} was broadcasted by {o}")
        elif p == "firstAired":
            parts.append(f"{s} first aired on {o}")
        elif p == "series":
            parts.append(f"{s} belongs to the series {o}")
        elif p == "child":
            parts.append(f"{s} has a child named {o}")
        else:
            parts.append(f"{s} {p} {o}")

    # Combine parts into one sentence
    if len(parts) == 1:
        sentence = parts[0] + "."
    else:
        sentence = ", ".join(parts[:-1]) + ", and " + parts[-1] + "."
    return sentence

